// // This module decrements the 4-bit counter on a positive clock edge and is reset asynchronously.
module binary_counter_4bit(
    input clk,
    input reset,
    output reg [3:0] count
);
    always @(posedge clk) begin
        if (reset)
            count <= 4'b0000;
        else
            count <= count + 1;
    end
endmodule
